  1	import * as React from 'react';
  2	import { getNooBaaState } from '@odf/ocs/dashboards/object-service/status-card/statuses';
  3	import { getCephsHealthState } from '@odf/ocs/utils';
  4	import { healthStateMapping } from '@odf/shared/dashboards';
  5	import { CephClusterModel } from '@odf/shared/models';
  6	import { PrometheusHealthHandler } from '@odf/shared/types';
  7	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  8	import { referenceForModel } from '@odf/shared/utils';
  9	import {
 10	  StatusPopupSection,
 11	  HealthState,
 12	  SubsystemHealth,
 13	  PrometheusHealthPopupProps,
 14	  FirehoseResource,
 15	  K8sResourceCommon,
 16	} from '@openshift-console/dynamic-plugin-sdk';
 17	import * as _ from 'lodash-es';
 18	import { Link } from 'react-router-dom-v5-compat';
 19	import { Stack, StackItem } from '@patternfly/react-core';
 20	import '@odf/shared/popup/status-popup.scss';
 21	
 22	export const getStorageSystemHealthState: PrometheusHealthHandler = (
 23	  promMetrics,
 24	  t,
 25	  ceph
 26	) => {
 27	  const isNoobaaOnly = _.isEmpty(ceph?.data);
 28	  if (!isNoobaaOnly) {
 29	    return getCephsHealthState(
 30	      {
 31	        ceph: {
 32	          data: ceph.data as K8sResourceCommon[],
 33	          loaded: ceph.loaded,
 34	          loadError: ceph.loadError,
 35	        },
 36	      },
 37	      t
 38	    );
 39	  } else {
 40	    return getNooBaaState(promMetrics, t, {
 41	      loaded: true,
 42	      loadError: '',
 43	      data: {},
 44	    });
 45	  }
 46	};
 47	
 48	export const StoragePopover: React.FC<PrometheusHealthPopupProps> = ({
 49	  responses,
 50	  k8sResult,
 51	}) => {
 52	  const { t } = useCustomTranslation();
 53	
 54	  const noobaaHealth = getNooBaaState(responses, t, {
 55	    loaded: true,
 56	    loadError: '',
 57	    data: {},
 58	  });
 59	  const cephData = k8sResult?.data;
 60	  const isNoobaaOnly = _.isEmpty(cephData);
 61	  const cephHealthState: SubsystemHealth = getCephsHealthState(
 62	    {
 63	      ceph: {
 64	        data: cephData as K8sResourceCommon[],
 65	        loaded: k8sResult?.loaded,
 66	        loadError: k8sResult?.loadError,
 67	      },
 68	    },
 69	    t
 70	  );
 71	  const healthStatus: HealthState = isNoobaaOnly
 72	    ? noobaaHealth?.state
 73	    : cephHealthState?.state;
 74	  const operatorName = t('Data Foundation');
 75	
 76	  return (
 77	    <Stack hasGutter>
 78	      <StackItem>
 79	        {t(
 80	          "Storage status represents the health status of Data Foundation's StorageCluster."
 81	        )}
 82	      </StackItem>
 83	      <StackItem>
 84	        <StatusPopupSection
 85	          firstColumn={t('Provider')}
 86	          secondColumn={t('Health')}
 87	        >
 88	          <div className="odf-status-popup__row">
 89	            <Link to="/odf/overview">{operatorName}</Link>
 90	            {healthStateMapping[healthStatus]?.icon}
 91	          </div>
 92	        </StatusPopupSection>
 93	      </StackItem>
 94	    </Stack>
 95	  );
 96	};
 97	
 98	export { getStorageSystemHealthState as healthHandler };
 99	
100	export const healthResource: FirehoseResource = {
101	  kind: referenceForModel(CephClusterModel),
102	  namespaced: false,
103	  isList: true,
104	  prop: 'ceph',
105	};

